---@class LBattleViewBuff
local LBattleViewBuff = classX("LBattleViewBuff", nil)
-----------------------------------------------------------------
local LBattleViewEffect = require("LApp.gameplay.videobattle.view.obj.LBattleViewEffect")

-----------------------------------------------------------------
function LBattleViewBuff:ctor(viewMgr)
    ---@type LBattleViewMgr
    self._viewMgr = viewMgr
    ---@type LBattleViewEffect
    self._effect = nil
    ---@type number
    self._buffId = -1
end

function LBattleViewBuff:GetBuffUniqueId()
    return self._buffUniqueId
end

---@param battleObj LBattleViewUnit
function LBattleViewBuff:ShowEffect(data,battleObj)
    self._buffUniqueId = data.buffUniqueId
    self._buffId = data.buffId or -1

    local parentTrans = data.root
    local pos = data.pos
    local effId = data.effectName
    local order = data.order
    local dir =  data.dir
    local localPos = data.localPos
    local scale = data.scale or 1
    ---@type LBattleViewEffect
    local eff = LBattleViewEffect:new(self._viewMgr)
    local idx = self._buffUniqueId
    eff:InitView(idx,parentTrans,effId,pos,dir,0,0,0,nil, nil)
    eff:SetEffectPara({
        order = order,localPos = localPos,scale = scale,buffId = self._buffId,
    })
    if battleObj then
        eff:SetTargetObj(battleObj)
    end
    eff:PlayEffect()
    self._effect = eff
end

function LBattleViewBuff:ResetOrder(order)
    if self._effect then
        self._effect:ResetRenderOrder(order)
    end
end

function LBattleViewBuff:SetVisible(isVisible,isEnd)
    if isVisible and isEnd and self:CheckIsHitShowBuff() then
        isVisible = false
    end
    if self._effect then
        self._effect:SetVisible(isVisible)
    end
end

function LBattleViewBuff:CheckIsHitShowBuff()
    if not self._buffId or self._buffId < 1 then return false end
    ---@type V_BuffRef
    local buffRef = GameTable.CombatBuffRef[self._buffId]
    if not buffRef then return false end
    return buffRef.buffEffShowTime == 2
end

function LBattleViewBuff:Dispose()
    if self._isDisposed then return end
    if self._effect then
        self._effect:Dispose()
    end
    self._effect = nil
    table.dispose(self)
    self._isDisposed = true
end

return LBattleViewBuff